class Solution:
    def countDigitOccurrences(self, nums, digit: int) -> int:
        target = str(digit)
        total = 0
        for x in nums:
            for ch in str(x):
                if ch == target:
                    total += 1
        return total

solutions.python:
class Solution:
    def countDigitOccurrences(self, nums, digit: int) -> int:
        total = 0
        for x in nums:
            while x > 0:
                if x % 10 == digit:
                    total += 1
                x //= 10
        return total

solutions.javascript:
var countDigitOccurrences = function(nums, digit) {
    let total = 0;
    for (let x of nums) {
        while (x > 0) {
            if (x % 10 === digit) total++;
            x = Math.floor(x / 10);
        }
    }
    return total;
};
